//#region src/hooks/useOptimizeRoute.ts
function useOptimizeRoute() {
	const [isOptimizing, setIsOptimizing] = (0, import_react.useState)(false);
	const { toast } = useToast();
	const optimizeRoute = async (origin, deliveries, startTime = "08:00", timePerDelivery = 30) => {
		setIsOptimizing(true);
		try {
			const { data, error } = await supabase.functions.invoke("optimize-route", { body: {
				origin,
				deliveries: deliveries.map((d) => ({
					id: d.id,
					codigo_obra: d.codigo_obra,
					cliente: d.cliente,
					endereco: d.endereco,
					responsavel_recebimento: d.responsavel_recebimento,
					telefone: d.telefone
				})),
				startTime,
				timePerDelivery
			} });
			if (error) throw new Error(error.message || "Erro ao otimizar rota");
			if (data.error) throw new Error(data.error);
			const originalDistance = deliveries.length * 5;
			const optimizedDistance = data.metricas?.distancia_total_km || 0;
			toast({
				title: "Rota otimizada! 🚀",
				description: `Economia estimada de ${Math.max(0, originalDistance - optimizedDistance).toFixed(1)} km`,
				className: "bg-success text-success-foreground border-none"
			});
			return data;
		} catch (err) {
			toast({
				title: "Erro na otimização",
				description: err instanceof Error ? err.message : "Erro ao otimizar rota",
				variant: "destructive"
			});
			return null;
		} finally {
			setIsOptimizing(false);
		}
	};
	return {
		optimizeRoute,
		isOptimizing
	};
}
