function calculatePasswordStrength(password) {
	const criteria = {
		minLength: password.length >= 8,
		hasUppercase: /[A-Z]/.test(password),
		hasLowercase: /[a-z]/.test(password),
		hasNumber: /[0-9]/.test(password),
		hasSpecial: /[!@#$%^&*(),.?":{}|<>]/.test(password)
	};
	const score = Object.values(criteria).filter(Boolean).length / 5 * 100;
	let label;
	let color;
	if (score <= 40) {
		label = "Fraca";
		color = "bg-destructive";
	} else if (score <= 70) {
		label = "Média";
		color = "bg-orange-500";
	} else {
		label = "Forte";
		color = "bg-green-500";
	}
	return {
		score,
		label,
		color,
		criteria
	};
}
